mapper.select:
select count(*)
from stock_tb
where product_id = #{productId}
  and size_id = #{sizeId}
  and color_id = #{colorId}

mapper.update:
update stock_tb
set
    count = count - #{quantity},
    is_sold_out = if(count - #{quantity} <= 0, 1, 0),
    updated_at = now()
where product_id = #{productId}
  and size_id = #{sizeId}
  and color_id = #{colorId}
  and count >= #{quantity}

update stock_tb
set
    count = count + #{quantity},
    is_sold_out = 0,
    updated_at = now()
where product_id = #{productId}
  and size_id = #{sizeId}
  and color_id = #{colorId}
